import React, { Suspense, lazy } from 'react';
import PageHeader from '../components/PageHeader';
import AssetIcon from '../components/AssetIcon';
import { LoadingState } from '../components/QueryStates';
import { PAGE_ICONS } from '../config/assetIcons';
import {
  OptimizationHubProvider,
  useOptimizationHub,
  OPTIMIZATION_HUB_TABS,
} from '../context/OptimizationHubContext';

const OptimizationHubOverview = lazy(() => import('../components/optimization/OptimizationHubOverview'));
const OptimizationAdvisorTab = lazy(() => import('../components/optimization/OptimizationAdvisorTab'));
const Recommendations = lazy(() => import('./Recommendations'));
const OptimizationActions = lazy(() => import('./OptimizationActions'));
const OptimizationScoreboard = lazy(() => import('./OptimizationScoreboard'));
const RolloutMonitor = lazy(() => import('./RolloutMonitor'));

function OptimizationHubTabs() {
  const { tab, setTab } = useOptimizationHub();

  return (
    <div className="optimization-hub-tabs" role="tablist" aria-label="Optimization hub">
      {OPTIMIZATION_HUB_TABS.map((item) => (
        <button
          key={item.id}
          type="button"
          role="tab"
          aria-selected={tab === item.id}
          className={`optimization-hub-tabs__tab${tab === item.id ? ' optimization-hub-tabs__tab--active' : ''}`}
          onClick={() => setTab(item.id)}
        >
          <AssetIcon iconKey={item.iconKey} size={15} alt="" />
          <span>{item.label}</span>
        </button>
      ))}
    </div>
  );
}

function OptimizationHubPanel() {
  const { tab } = useOptimizationHub();

  return (
    <Suspense fallback={<LoadingState message="Loading…" />}>
      {tab === 'overview' && <OptimizationHubOverview />}
      {tab === 'recommendations' && <Recommendations embedded />}
      {tab === 'advisor' && <OptimizationAdvisorTab />}
      {tab === 'actions' && <OptimizationActions embedded />}
      {tab === 'scoreboard' && <OptimizationScoreboard embedded />}
      {tab === 'monitor' && <RolloutMonitor embedded />}
    </Suspense>
  );
}

export default function OptimizationHub() {
  return (
    <OptimizationHubProvider>
      <div className="page-shell optimization-hub-page">
        <PageHeader
          title="Optimization hub"
          subtitle="Findings, Advisor, actions, and rollout in one place"
          iconKey={PAGE_ICONS.actions}
        />
        <OptimizationHubTabs />
        <div className="optimization-hub-panel" role="tabpanel">
          <OptimizationHubPanel />
        </div>
      </div>
    </OptimizationHubProvider>
  );
}
